"""Базовый класс шумов + единая нормировка к target SNR + провенанс."""from __future__ import annotationsfrom typing import Anyimport numpy as npfrom ..core.interfaces import INoisefrom ..core.types import Signal_ALLOWED_TYPES = {"int", "float", "bool", "enum"}def _check_schema(schema: dict[str, dict[str, Any]]) -> None:    if not isinstance(schema, dict) or not schema:        raise ValueError("params_schema must be a non-empty dict")    if "target_snr_db" not in schema:        raise ValueError("noise params_schema must contain 'target_snr_db'")    for key, spec in schema.items():        if not isinstance(spec, dict):            raise ValueError(f"Param '{key}': spec must be dict")        t = spec.get("type")        if t not in _ALLOWED_TYPES:            raise ValueError(f"Param '{key}': bad 'type' ({t!r})")        if "default" not in spec:            raise ValueError(f"Param '{key}': missing 'default'")        if "label" not in spec or not isinstance(spec["label"], str):            raise ValueError(f"Param '{key}': missing string 'label'")        if t in ("int", "float"):            if "min" not in spec or "max" not in spec:                raise ValueError(f"Param '{key}': numeric requires min/max")            if spec["max"] <= spec["min"]:                raise ValueError(f"Param '{key}': max must be > min")            if not (spec["min"] <= spec["default"] <= spec["max"]):                raise ValueError(f"Param '{key}': default out of [min, max]")        if t == "enum":            choices = spec.get("choices")            if not isinstance(choices, (list, tuple)) or not choices:                raise ValueError(f"Param '{key}': enum requires non-empty 'choices'")            if spec["default"] not in choices:                raise ValueError(f"Param '{key}': default not in choices")def _fill_and_validate(params: dict[str, Any],                       schema: dict[str, dict[str, Any]]) -> dict[str, Any]:    extras = set(params) - set(schema)    if extras:        raise ValueError(f"Unknown params: {sorted(extras)}")    out: dict[str, Any] = {}    for key, spec in schema.items():        raw = params.get(key, spec["default"])        t = spec["type"]        try:            if t == "int":                val: Any = int(raw)            elif t == "float":                val = float(raw)            elif t == "bool":                val = bool(raw)            else:                val = str(raw)        except (TypeError, ValueError) as e:            raise ValueError(f"Param '{key}': cannot cast {raw!r} to {t} ({e})") from e        if t in ("int", "float") and not (spec["min"] <= val <= spec["max"]):            raise ValueError(                f"Param '{key}'={val} out of [{spec['min']}, {spec['max']}]"            )        if t == "enum" and val not in spec["choices"]:            raise ValueError(f"Param '{key}'={val!r} not in {spec['choices']}")        out[key] = val    return outdef _validate_input_signal(signal: Signal) -> None:    if not isinstance(signal, Signal):        raise TypeError("expected Signal instance")    if signal.x.size == 0:        raise ValueError("input signal is empty")    if signal.t.size != signal.x.size:        raise ValueError("len(t) != len(x) in input signal")    if not np.all(np.isfinite(signal.x)):        raise ValueError("input signal contains NaN/Inf")def _mean_power(a: np.ndarray) -> float:    return float(np.mean(a * a))def _snr_scale(p_clean: float, p_raw: float, target_snr_db: float) -> float:    if p_clean <= 0.0:        raise ValueError("мощность чистого сигнала равна нулю — SNR не определён")    if p_raw <= 0.0:        raise ValueError("мощность сырого шума равна нулю — нормировка к SNR невозможна")    p_target = p_clean / (10.0 ** (target_snr_db / 10.0))    return float(np.sqrt(p_target / p_raw))class BaseNoise(INoise):    def __init_subclass__(cls, **kwargs: Any) -> None:        super().__init_subclass__(**kwargs)        schema = getattr(cls, "params_schema", None)        if schema is not None:            _check_schema(schema)        name = getattr(cls, "name", None)        if not isinstance(name, str) or not name.strip():            raise ValueError(f"{cls.__name__}: 'name' must be a non-empty string")        desc = getattr(cls, "description", None)        if not isinstance(desc, str) or not desc:            raise ValueError(f"{cls.__name__}: 'description' must be a non-empty string")    def apply(self, signal: Signal, **params: Any) -> Signal:        _validate_input_signal(signal)        p = _fill_and_validate(params, self.params_schema)        rng = np.random.default_rng(int(p["seed"]))        raw = self._generate_raw(signal, p, rng)        raw = np.asarray(raw, dtype=np.float64)        if raw.shape != signal.x.shape:            raise ValueError(                f"{self.name}: raw noise shape {raw.shape} != signal {signal.x.shape}"            )        if not np.all(np.isfinite(raw)):            raise ValueError(f"{self.name}: raw noise contains NaN/Inf")        target_snr_db = float(p["target_snr_db"])        p_clean = _mean_power(signal.x)        p_raw = _mean_power(raw)        k = _snr_scale(p_clean, p_raw, target_snr_db)        noise = k * raw        noisy_x = (signal.x + noise).astype(np.float64, copy=False)        p_noise_actual = _mean_power(noise)        measured_snr_db = 10.0 * np.log10(p_clean / p_noise_actual)        out_params: dict[str, Any] = {            "noise_name": self.name,            "target_snr_db": target_snr_db,            "measured_snr_db": float(measured_snr_db),        }        for k2, v in p.items():            if k2 != "target_snr_db":                out_params[k2] = v        out_params["upstream"] = dict(signal.params)        return Signal(            t=signal.t.copy(), x=noisy_x, fs=signal.fs,            name=signal.name, params=out_params,        )    def _generate_raw(self, clean: Signal, p: dict[str, Any],                      rng: np.random.Generator) -> np.ndarray:        raise NotImplementedError